type userStore struct {
	mu    sync.RWMutex
	users map[string]*User
	seq   int64
}

type orderStore struct {
	mu     sync.RWMutex
	orders map[string]*Order
	seq    int64
}

type paymentStore struct {
	mu       sync.RWMutex
	payments map[string]*Payment
	seq      int64
}

type userService struct{ us *userStore }
type orderService struct {
	us *userStore
	os *orderStore
}
type paymentService struct {
	os *orderStore
	ps *paymentStore
}

func newUserStore() *userStore { return &userStore{users: map[string]*User{}} }
func newOrderStore() *orderStore { return &orderStore{orders: map[string]*Order{}} }
func newPaymentStore() *paymentStore { return &paymentStore{payments: map[string]*Payment{}} }

func nowUnix() int64 { return time.Now().Unix() }

func (s *userService) CreateUser(ctx context.Context, req *CreateUserRequest) (*CreateUserResponse, error) {
	if strings.TrimSpace(req.GetName()) == "" {
		return nil, status.Error(codes.InvalidArgument, "name is required")
	}
	if strings.TrimSpace(req.GetEmail()) == "" {
		return nil, status.Error(codes.InvalidArgument, "email is required")
	}

	s.us.mu.Lock()
	defer s.us.mu.Unlock()
	s.us.seq++
	id := fmt.Sprintf("u_%d", s.us.seq)
	u := &User{
		Id:        id,
		Name:      req.Name,
		Email:     req.Email,
		CreatedAt: nowUnix(),
	}
	s.us.users[id] = u
	return &CreateUserResponse{User: u}, nil
}

func (s *userService) GetUser(ctx context.Context, req *GetUserRequest) (*GetUserResponse, error) {
	if strings.TrimSpace(req.GetId()) == "" {
		return nil, status.Error(codes.InvalidArgument, "id is required")
	}
	s.us.mu.RLock()
	defer s.us.mu.RUnlock()
	u := s.us.users[req.Id]
	if u == nil {
		return nil, status.Error(codes.NotFound, "user not found")
	}
	return &GetUserResponse{User: cloneUser(u)}, nil
}

func (s *userService) ListUsers(ctx context.Context, _ *ListUsersRequest) (*ListUsersResponse, error) {
	s.us.mu.RLock()
	defer s.us.mu.RUnlock()
	out := make([]*User, 0, len(s.us.users))
	for _, u := range s.us.users {
		out = append(out, cloneUser(u))
	}
	return &ListUsersResponse{Users: out}, nil
}

func (s *userService) DeleteUser(ctx context.Context, req *DeleteUserRequest) (*DeleteUserResponse, error) {
	if strings.TrimSpace(req.GetId()) == "" {
		return nil, status.Error(codes.InvalidArgument, "id is required")
	}
	s.us.mu.Lock()
	defer s.us.mu.Unlock()
	if _, ok := s.us.users[req.Id]; !ok {
		return nil, status.Error(codes.NotFound, "user not found")
	}
	delete(s.us.users, req.Id)
	return &DeleteUserResponse{Deleted: true}, nil
}

func (s *orderService) CreateOrder(ctx context.Context, req *CreateOrderRequest) (*CreateOrderResponse, error) {
	if strings.TrimSpace(req.GetUserId()) == "" {
		return nil, status.Error(codes.InvalidArgument, "user_id is required")
	}
	if len(req.Items) == 0 {
		return nil, status.Error(codes.InvalidArgument, "items are required")
	}
	for i, it := range req.Items {
		if it == nil || strings.TrimSpace(it.Sku) == "" || it.Quantity <= 0 || it.PriceCents < 0 {
			return nil, status.Errorf(codes.InvalidArgument, "invalid item at index %d", i)
		}
	}

	s.us.mu.RLock()
	_, ok := s.us.users[req.UserId]
	s.us.mu.RUnlock()
	if !ok {
		return nil, status.Error(codes.NotFound, "user not found")
	}

	total := int64(0)
	items := make([]*OrderItem, 0, len(req.Items))
	for _, it := range req.Items {
		total += int64(it.Quantity) * it.PriceCents
		items = append(items, &OrderItem{Sku: it.Sku, Quantity: it.Quantity, PriceCents: it.PriceCents})
	}

	s.os.mu.Lock()
	defer s.os.mu.Unlock()
	s.os.seq++
	id := fmt.Sprintf("o_%d", s.os.seq)
	ts := nowUnix()
	o := &Order{
		Id:         id,
		UserId:     req.UserId,
		Status:     "PENDING",
		Items:      items,
		TotalCents: total,
		CreatedAt:  ts,
		UpdatedAt:  ts,
	}
	s.os.orders[id] = o
	return &CreateOrderResponse{Order: cloneOrder(o)}, nil
}

