func validateListenAddr(addr string) (string, error) {
	a := strings.TrimSpace(addr)
	if a == "" {
		return "", errors.New("empty address")
	}
	if !strings.Contains(a, ":") {
		return "", errors.New("address must include port (e.g. :50051)")
	}
	return a, nil
}

func main() {
	addr, err := validateListenAddr(":50051")
	if err != nil {
		log.Fatal(err)
	}

	us := newUserStore()
	os := newOrderStore()
	ps := newPaymentStore()

	grpcServer := grpc.NewServer()

	RegisterUserServiceServer(grpcServer, &userService{us: us})
	RegisterOrderServiceServer(grpcServer, &orderService{us: us, os: os})
	RegisterPaymentServiceServer(grpcServer, &paymentService{os: os, ps: ps})

	reflection.Register(grpcServer)

	lis, err := net.Listen("tcp", addr)
	if err != nil {
		log.Fatalf("listen error: %v", err)
	}
	log.Printf("gRPC dev server listening on %s", addr)
	if err := grpcServer.Serve(lis); err != nil {
		log.Fatalf("serve error: %v", err)
	}
}